PlayerListener = {}

local TrackerGroupIndex = 1000
local LogoutTimerKey = 0

function PlayerListener:init()
    BaseListener.registerCallBack(PlayerLoginEvent, self.onPlayerLogin)
    BaseListener.registerCallBack(PlayerLogoutEvent, self.onPlayerLogout)
    BaseListener.registerCallBack(PlayerReadyEvent, self.onPlayerReady)
    BaseListener.registerCallBack(PlayerAttackedEvent, self.onPlayerHurt)
    BaseListener.registerCallBack(PlayerDieEvent, self.onPlayerDied)

    PlayerDieEvent.registerCallBack(function()
        return false
    end)
    BlockBreakEvent.registerCallBack(self.onBlockBreak)

    PlaceTowerEvent:registerCallBack(self.onPlayerPlaceTower)

    LockTowerEvent:registerCallBack(self.onPlayerLockTower)
    SellTowerEvent:registerCallBack(self.onPlayerSellTower)
    SupportTeammateEvent:registerCallBack(self.onPlayerSupportTeammate)
    RequestLogoutEvent:registerCallBack(self.onPlayerRequestLogout)
    RequestPlayAgainEvent:registerCallBack(self.onPlayerRequestPlayAgain)

    C2SOpenBookDetail:registerCallBack(self.onOpenBookDetail)
    C2SBuyPaySkill:registerCallBack(self.onBuyPaySkill)
    C2SBuyShopItem:registerCallBack(self.onBuyShopItem)
    C2SExchangeHallGold:registerCallBack(self.exchangeHallGold)
    C2SBuyPayItem:registerCallBack(self.onBuyPayItem)
    C2SSetShortCurBar:registerCallBack(self.setShortCurBar)

    ReceiveSumRechargeEvent:registerCallBack(self.onReceiveSumRecharge)
    ReceiveSumRechargeEndEvent:registerCallBack(self.onReceiveSumRechargeEnd)
    PlayerIntoFollowModeEvent:registerCallBack(self.onPlayerIntoFollowMode)
end

function PlayerListener.onPlayerLogin(clientPeer)
    local player = GamePlayer.new(clientPeer)
    player:init()
    ProcessManager:subPlayer(player)
    HostApi.sendGameStatus(player.rakssid, 1)
    TrackerGroupIndex = TrackerGroupIndex + 1
    player.entityPlayerMP:setIntProperty("TrackerGroupId", TrackerGroupIndex)
    return GameOverCode.Success, player
end

function PlayerListener.onPlayerLogout(player)
    player:onLogout()
    ProcessManager:subPlayer(player)
    HallManager:onPlayerLogout(player)
    if PlayerManager:getPlayerCount() == 0 then
        ---延迟120s后若还是没有人 关闭服务器
        LuaTimer:cancel(LogoutTimerKey)
        LogoutTimerKey = LuaTimer:schedule(function()
            if PlayerManager:getPlayerCount() == 0 then
                GameServer:closeServer()
            end
        end, 120000)
    end
end

function PlayerListener.onPlayerReady(player)
    DbUtil:getPlayerData(player)
    ProcessManager:addPlayer(player)     --添加玩家
    GamePacketSender:sendTowerCanBuildList(player.rakssid, GameConfig.initTowers)
    HostApi.sendSetMoveState(player.rakssid, 2)
    player.entityPlayerMP:setSpeedAdditionLevel(GameConfig.AddSpeed)
    return 43200
end

function PlayerListener.onPlayerHurt(hurtPlayer, hurtFrom, damageType, hurtValue)
    return false
end

function PlayerListener.onPlayerDied(diePlayer, iskillByPlayer, killPlayer)
    return true
end

function PlayerListener.onBlockBreak(rakssid, blockId, blockMeta, blockPos)
    return false
