function PlayerListener.onPlayerPlaceTower(userId, data)
    local player = PlayerManager:getPlayerByUserId(userId)
    if not player then
        return
    end
    local builder = DataBuilder.new():fromData(data)
    local pos = builder:getVector3iParam("pos")
    local configId = builder:getNumberParam("Id")
    local config = TowerConfig:getConfigById(configId)
    if config then
        player:tryPlaceTower(pos, config)
    end
end

function PlayerListener.onPlayerLockTower(userId, data)
    local player = PlayerManager:getPlayerByUserId(userId)
    if not player then
        return
    end
    local builder = DataBuilder.new():fromData(data)
    local entityId = builder:getNumberParam("entityId")
    local isLock = builder:getBoolParam("isLock")
    local tower = LuaEntityManager:getTower(entityId)
    if tower ~= nil then
        tower:setLocked(userId, isLock)
    end
end

function PlayerListener.onPlayerSellTower(userId, data)
    local player = PlayerManager:getPlayerByUserId(userId)
    if not player then
        return
    end
    local builder = DataBuilder.new():fromData(data)
    local entityId = builder:getNumberParam("entityId")
    local tower = LuaEntityManager:getTower(entityId)
    if tower ~= nil then
        tower:onSell(userId)
    end
end

function PlayerListener.onPlayerSupportTeammate(userId, data)
    local player = PlayerManager:getPlayerByUserId(userId)
    local builder = DataBuilder.new():fromData(data)
    local teammateUserId = builder:getNumberParam("mateUserId")
    local teammate = PlayerManager:getPlayerByUserId(teammateUserId)

    if not player or not teammate then
        return
    end
    local moneyNum = builder:getNumberParam("moneyNum")

    if player.Wallet:costMoney(Define.Money.GameGold, moneyNum) then
        teammate.Wallet:addMoney(Define.Money.GameGold, moneyNum)
        local process = ProcessManager:getProcessByProcessId(player.processId)
        if process then
            local lang = teammate:getLanguage()
            local text = tostring(player.name) .. TextFormat.argsSplit .. tostring(moneyNum)
            local str = MultiLanTipSetting.getMessageToLua(lang, 1056003, text)
            MsgSender.sendCenterTipsToTarget(teammate.rakssid, 3, str)
            process:broadCastSupportInfo(player.name, teammate.name, moneyNum)
        end
    end

    ReportUtil.reportClickSupportSure(player)
end

function PlayerListener.onPlayerRequestLogout(userId)
    local player = PlayerManager:getPlayerByUserId(userId)
    if player == nil then
        return
    end
    local process = ProcessManager:getProcessByProcessId(player.processId)
    if process then
        process:requestPlayAgain(userId, false)
    end
    HallManager:addEnterRoomQueue(player)
end

function PlayerListener.onPlayerRequestPlayAgain(userId)
    local player = PlayerManager:getPlayerByUserId(userId)
    if player == nil then
        return
    end
    local process = ProcessManager:getProcessByProcessId(player.processId)
    if process then
        process:requestPlayAgain(userId, true)
    end
end

