function PlayerListener.setShortCurBar(userId, data)
    local player = PlayerManager:getPlayerByUserId(userId)
    if player == nil then
        return
    end

    local builder = DataBuilder.new():fromData(data)
    local BarId = builder:getNumberParam("BarId")
    local TowerId = builder:getNumberParam("TowerId")
    if player.shortCutBar == nil then
        player.shortCutBar = {}
    end
    player.shortCutBar[tostring(BarId)] = TowerId
end

function PlayerListener.onReceiveSumRecharge(player, type, id, count, meta)
    local reward = {
        RewardId = tonumber(id) or 0,
        RewardType = tonumber(type) or 0,
        RedressRewardId = 0,
        Count = tonumber(count) or 0,
        Time = 0,
        IsNotification = false,
        NotificationContent = ""
    }

    GameReward:onPlayerGetReward(player, reward)

    if tonumber(type) == Define.RewardType.Tower and player.payItemList[tostring(Define.PayStoreItem.ShortcutBarOne)] then
        if player.shortCutBar == nil then
            player.shortCutBar = {}
        end
        player.shortCutBar[tostring(2001)] = tonumber(id)
        player:addNewTowerBook(tonumber(id))
        GamePacketSender:sendTowerDefenseGetNewTower(player.rakssid, player.towerList[tonumber(id)])
        GamePacketSender:sendShortCutBarSetting(player.rakssid, player.shortCutBar)
    end
end

function PlayerListener.onReceiveSumRechargeEnd(player, id)
    ReportUtil.reportFirstRecharge(player, id)
end

function PlayerListener.onPlayerIntoFollowMode(player, follower)
